# pip install anthropic
import imaplib, email, time
from email.header import decode_header
from anthropic import Anthropic

client = Anthropic()

def decode_str(value: str | bytes | None) -> str:
    if value is None:
        return ""
    if isinstance(value, bytes):
        return value.decode("utf-8", errors="replace")
    return value

def parse_email(raw: bytes) -> dict:
    msg = email.message_from_bytes(raw)
    subject_parts = decode_header(msg.get("Subject", ""))
    subject = " ".join(decode_str(part) for part, enc in subject_parts)
    sender = msg.get("From", "")
    body = ""
    if msg.is_multipart():
        for part in msg.walk():
            if part.get_content_type() == "text/plain":
                body = decode_str(part.get_payload(decode=True))
                break
    else:
        body = decode_str(msg.get_payload(decode=True))
    return {"subject": subject, "from": sender, "body": body[:3000]}  # Cap length

def classify_email(parsed: dict) -> str:
    resp = client.messages.create(
        model="claude-haiku-4-5-20251001",
        max_tokens=50,
        messages=[{
            "role": "user",
            "content": (
                f"Subject: {parsed['subject']}\n"
                f"From: {parsed['from']}\n"
                f"Body: {parsed['body'][:500]}\n\n"
                "Classify this email as one of: support_request, billing, spam, other. "
                "Reply with exactly one word."
            )
        }]
    )
    return resp.content[0].text.strip().lower()

def poll_inbox(imap_host: str, username: str, password: str, interval: int = 60):
    while True:
        with imaplib.IMAP4_SSL(imap_host) as imap:
            imap.login(username, password)
            imap.select("INBOX")
            _, uids = imap.search(None, "UNSEEN")
            for uid in uids[0].split():
                _, data = imap.fetch(uid, "(RFC822)")
                raw = data[0][1]
                parsed = parse_email(raw)
                category = classify_email(parsed)
                print(f"[{category}] {parsed['subject']} from {parsed['from']}")
                imap.store(uid, "+FLAGS", "\Seen")
        time.sleep(interval)

