from anthropic import Anthropic
import json

client = Anthropic()

ROUTE_MAP = {
    "billing": "billing-team@acme.com",
    "technical_support": "support@acme.com",
    "sales": "sales@acme.com",
    "legal": "legal@acme.com",
    "spam": None,  # Discard
}

def triage_email(email: dict) -> dict:
    resp = client.messages.create(
        model="claude-haiku-4-5-20251001",
        max_tokens=150,
        messages=[{
            "role": "user",
            "content": (
                f"Subject: {email['subject']}\nBody: {email['body'][:800]}\n\n"
                "Classify this email. Respond with JSON only:\n"
                '{"category": "billing|technical_support|sales|legal|spam", '
                '"confidence": 0.0-1.0, "summary": "one sentence"}'
            )
        }]
    )
    try:
        result = json.loads(resp.content[0].text)
    except json.JSONDecodeError:
        result = {"category": "technical_support", "confidence": 0.5, "summary": "parse error"}

    category = result.get("category", "technical_support")
    confidence = result.get("confidence", 0.5)

    if confidence < 0.7:
        # Low confidence: route to human review queue
        return {**result, "route_to": "human-review@acme.com", "needs_review": True}

    route = ROUTE_MAP.get(category)
    return {**result, "route_to": route, "needs_review": False}

